def stock_span(prices):
    spans = []
    stack = []  # (price, index)
    for i, price in enumerate(prices):
        while stack and stack[-1][0] <= price:
            stack.pop()
        span = i - stack[-1][1] if stack else i + 1
        spans.append(span)
        stack.append((price, i))
    return spans
